        HashMap<String, Integer> scores = new HashMap<>();
        scores.put("Alice", 88);
        scores.put("Bob", 75);
        scores.put("Carol", 92);
        scores.put("Dave", 65);

        System.out.println("--- Scores ---");
        // Use entrySet() to iterate and print each: "Alice: 88"

        int total = 0;
        // Use values() collection to sum all scores
        System.out.println("Total: " + total);
